import { describe, expect, it } from 'vitest';
import {
  THOTH_KEN_MARGIN_FRAME_KIND,
  THOTH_KEN_THEOREM_REFS,
  encodeThothKenMarginFrame,
  isThothKenMarginFrame,
  ken,
  renderThothKenConfession,
  renderThothKenMarginPromptContext,
  thothKenMarginMetrics,
  thothSpeechGate,
  thothSpeechGateAtSaturation,
  toleranceAtSaturation,
  withinKen,
} from '../src/thoth-ken-margin';

describe('Thoth ken-margin speech gate', () => {
  it('ken is the largest tolerance the margin provably absorbs', () => {
    expect(ken(10)).toBe(5);
    expect(ken(9)).toBe(4);
    expect(ken(0)).toBe(0);
    expect(withinKen(10, 5)).toBe(true);
    expect(withinKen(10, 6)).toBe(false);
    expect(withinKen(9, 4)).toBe(true);
    expect(withinKen(9, 5)).toBe(false);
  });

  it('speaks exactly on the Lean bound 2*tau <= gamma and confesses beyond it', () => {
    const speak = thothSpeechGate(10, 5);
    expect(speak.decision).toBe('speak');
    expect(speak.overshoot).toBe(0);
    expect(speak.theoremRef).toBe(THOTH_KEN_THEOREM_REFS.speak);

    const confess = thothSpeechGate(10, 6);
    expect(confess.decision).toBe('confess');
    expect(confess.overshoot).toBe(2);
    expect(confess.theoremRef).toBe(THOTH_KEN_THEOREM_REFS.confess);
  });

  it('tolerance is monotone in saturation and confess is absorbing', () => {
    const calibration = {
      baseTolerance: 1,
      saturationNumerator: 1,
      saturationDenominator: 1024,
    };
    expect(toleranceAtSaturation(0, calibration)).toBe(1);
    expect(toleranceAtSaturation(1024, calibration)).toBe(2);
    expect(toleranceAtSaturation(8192, calibration)).toBe(9);

    let previousConfessed = false;
    for (let saturation = 0; saturation <= 16384; saturation += 1024) {
      const decision = thothSpeechGateAtSaturation(8, saturation, calibration);
      if (previousConfessed) {
        expect(decision.decision).toBe('confess');
      }
      previousConfessed = decision.decision === 'confess';
    }
    expect(previousConfessed).toBe(true);
  });

  it('the confession carries the proof of its own honesty', () => {
    const confession = renderThothKenConfession(thothSpeechGate(2, 3));
    expect(confession).toContain('beyond my ken');
    expect(confession).toContain(THOTH_KEN_THEOREM_REFS.confess);
    expect(confession).toContain(THOTH_KEN_THEOREM_REFS.flipWitness);

    const sighting = renderThothKenConfession(thothSpeechGate(10, 2));
    expect(sighting).toContain('Within my ken');
    expect(sighting).toContain(THOTH_KEN_THEOREM_REFS.speak);
  });

  it('encodes a non-authoritative miss-not-lie frame', () => {
    const metrics = thothKenMarginMetrics(thothSpeechGate(10, 6), 8192);
    expect(metrics.missNotLie).toBe(true);
    expect(metrics.nonAuthoritative).toBe(true);

    const frame = encodeThothKenMarginFrame('thoth-host', metrics);
    expect(isThothKenMarginFrame(frame)).toBe(true);
    expect(frame.mediaType.Abstract).toBe(THOTH_KEN_MARGIN_FRAME_KIND);
    expect(frame.deficit).toBe(2);
    expect(frame.attributes.speech_decision).toBe('confess');
    expect(frame.attributes.ken).toBe('5');
    expect(frame.attributes.miss_not_lie).toBe('true');
    expect(frame.attributes.non_authoritative).toBe('true');

    const context = renderThothKenMarginPromptContext(metrics);
    expect(context).toContain('kind=thoth.ken-margin.v1');
    expect(context).toContain('decision=confess');
    expect(context).toContain('miss, not lie');
  });
});
